import{_ as a,c as o,o as t,a1 as d}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"부록: 참조 가이드 | oh-my-opencode","description":"oh-my-opencode 구성 옵션, Claude Code 호환성, 내장 MCP 서버를 마스터하세요. 이 참조 가이드는 마이그레이션 단계와 검색 기능을 다루어 OpenCode 환경을 사용자 정의하고 AI 워크플로우를 확장하는 방법을 설명합니다.","frontmatter":{"title":"부록: 참조 가이드 | oh-my-opencode","sidebarTitle":"부록","subtitle":"부록: 참조 가이드 및 호환성","description":"oh-my-opencode 구성 옵션, Claude Code 호환성, 내장 MCP 서버를 마스터하세요. 이 참조 가이드는 마이그레이션 단계와 검색 기능을 다루어 OpenCode 환경을 사용자 정의하고 AI 워크플로우를 확장하는 방법을 설명합니다.","tags":["부록","참조"],"order":170},"headers":[],"relativePath":"ko/code-yeongyu/oh-my-opencode/appendix/index.md","filePath":"ko/code-yeongyu/oh-my-opencode/appendix/index.md"}'),i={name:"ko/code-yeongyu/oh-my-opencode/appendix/index.md"};function l(r,e,n,c,h,s){return t(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="부록-참조-가이드-및-호환성" tabindex="-1">부록: 참조 가이드 및 호환성 <a class="header-anchor" href="#부록-참조-가이드-및-호환성" aria-label="Permalink to &quot;부록: 참조 가이드 및 호환성&quot;">​</a></h1><p>이 장은 <strong>oh-my-opencode</strong>에 대한 상세한 참조 자료와 호환성 가이드라인을 포함하며, 전체 구성 문서, Claude Code 마이그레이션 지원, 내장 확장 서버에 대한 상세한 소개를 다룹니다.</p><h2 id="장-내용" tabindex="-1">장 내용 <a class="header-anchor" href="#장-내용" aria-label="Permalink to &quot;장 내용&quot;">​</a></h2><p>이 장에는 세 가지 중요한 섹션이 포함되어 있습니다:</p><table tabindex="0"><thead><tr><th>하위 페이지</th><th>설명</th><th>난이도</th></tr></thead><tbody><tr><td><a href="./claude-code-compatibility/">Claude Code 호환성</a></td><td>Claude Code에서 OpenCode로 마이그레이션하는 완전한 가이드, Commands, Skills, Agents, MCPs, Hooks에 대한 호환성 메커니즘 포함</td><td>⭐⭐</td></tr><tr><td><a href="./configuration-reference/">구성 참조</a></td><td>oh-my-opencode 구성 파일의 완전한 스키마 문서, 모든 필드, 유형, 기본값 다룸</td><td>⭐⭐⭐</td></tr><tr><td><a href="./builtin-mcps/">내장 MCP</a></td><td>3개의 내장 MCP 서버(Exa Websearch, Context7, Grep.app)의 기능 및 사용법</td><td>⭐⭐</td></tr></tbody></table><h2 id="추천-학습-경로" tabindex="-1">추천 학습 경로 <a class="header-anchor" href="#추천-학습-경로" aria-label="Permalink to &quot;추천 학습 경로&quot;">​</a></h2><p>요구 사항에 따라 학습 순서를 선택하세요:</p><h3 id="경로-1-claude-code에서-마이그레이션" tabindex="-1">경로 1: Claude Code에서 마이그레이션 <a class="header-anchor" href="#경로-1-claude-code에서-마이그레이션" aria-label="Permalink to &quot;경로 1: Claude Code에서 마이그레이션&quot;">​</a></h3><p>Claude Code에서 마이그레이션하는 사용자인 경우:</p><ol><li>먼저 **<a href="./claude-code-compatibility/">Claude Code 호환성</a>**을 읽어 기존 구성을 원활하게 마이그레이션하는 방법을 이해하세요</li><li>그 다음 **<a href="./configuration-reference/">구성 참조</a>**을 검토하여 사용 가능한 구성 옵션을 더 깊이 이해하세요</li><li>마지막으로 **<a href="./builtin-mcps/">내장 MCP</a>**를 학습하여 추가 검색 기능을 구성하는 방법을 이해하세요</li></ol><h3 id="경로-2-깊은-사용자-정의" tabindex="-1">경로 2: 깊은 사용자 정의 <a class="header-anchor" href="#경로-2-깊은-사용자-정의" aria-label="Permalink to &quot;경로 2: 깊은 사용자 정의&quot;">​</a></h3><p>oh-my-opencode 동작을 깊이 사용자 정의하려는 경우:</p><ol><li>**<a href="./configuration-reference/">구성 참조</a>**부터 시작하여 모든 구성 가능 항목을 이해하세요</li><li>**<a href="./builtin-mcps/">내장 MCP</a>**를 학습하여 검색 및 문서 쿼리 기능을 구성하세요</li><li>**<a href="./claude-code-compatibility/">Claude Code 호환성</a>**을 참조하여 호환성 레이어 구성 옵션을 이해하세요</li></ol><h3 id="경로-3-빠른-참조" tabindex="-1">경로 3: 빠른 참조 <a class="header-anchor" href="#경로-3-빠른-참조" aria-label="Permalink to &quot;경로 3: 빠른 참조&quot;">​</a></h3><p>특정 정보만 조회해야 하는 경우:</p><ul><li><strong>구성 질문</strong> → **<a href="./configuration-reference/">구성 참조</a>**로 바로 이동</li><li><strong>마이그레이션 질문</strong> → **<a href="./claude-code-compatibility/">Claude Code 호환성</a>**로 바로 이동</li><li><strong>MCP 구성</strong> → **<a href="./builtin-mcps/">내장 MCP</a>**로 바로 이동</li></ul><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><p>이 장을 학습하기 위해 다음을 완료했는지 권장합니다:</p><ul><li>✅ <strong><a href="./../../ko/code-yeongyu/oh-my-opencode/start/installation/">설치 및 구성</a></strong> 완료</li><li>✅ **<a href="./../../ko/code-yeongyu/oh-my-opencode/start/sisyphus-orchestrator/">Sisyphus Orchestrator</a>**의 기본 개념 이해</li><li>✅ JSON 구성 파일 편집에 익숙함</li></ul><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 완료한 후 다음을 수행할 수 있습니다:</p><ul><li>🚀 **<a href="./../../ko/code-yeongyu/oh-my-opencode/advanced/">고급 기능</a>**을 시도하여 더 고급 사용법을 학습하세요</li><li>🔧 **<a href="./../../ko/code-yeongyu/oh-my-opencode/faq/">FAQ</a>**를 확인하여 사용 문제를 해결하세요</li><li>📖 **<a href="./../../ko/code-yeongyu/oh-my-opencode/changelog/">변경 로그</a>**를 읽어 새로운 기능 개선 사항을 최신으로 유지하세요</li></ul><div class="tip custom-block"><p class="custom-block-title">팁</p><p>이 장의 내용은 주로 참조 자료로 제공되므로 순차적으로 읽을 필요가 없습니다. 필요에 따라 관련 섹션을 참조하세요.</p></div>',23)])])}const m=a(i,[["render",l]]);export{u as __pageData,m as default};
